API_name: nchu_course_search_by_keyword
Description:
{
  "description": "依關鍵字搜尋中興大學課程資料庫中的課程。",
  "required_parameters": [
    {
      "name": "keyword",
      "type": "STRING",
      "description": "搜尋關鍵字"
    }
  ],
  "optional_parameters": [
    {
      "name": "limit",
      "type": "NUMBER",
      "description": "最多回傳幾筆結果（預設為 10）",
      "default": 10
    },
    {
      "name": "search_fields",
      "type": "STRING",
