API_name: nchu_course_search_across_semesters
Description:
{
  "description": "跨學期搜尋課程。適用於尋找歷史開課紀錄。注意：若搜尋所有學期，因採隨選載入資料，速度可能較慢。回傳包含依學期分組之搜尋結果的 JSON 字串",
  "required_parameters": [
    {
      "name": "keyword",
      "type": "STRING",
      "description": "搜尋關鍵字（課程名稱、教師姓名等）"
    }
  ],
  "optional_parameters": [
    {
      "name": "limit_per_semester",
      "type": "NUMBER",
      "description": "每學期最多回傳幾筆結果（預設為 10）",
      "default": 10
    },
    {
      "name": "search_fields",
      "type": "STRING",
      "description": "以逗號分隔的搜尋欄位（預設：科目名稱,上課教師,開課單位）",
      "default": null
    },
    {
      "name": "semesters",
      "type": "STRING",
      "description": "以逗號分隔的學年期代碼（例如：「1142,1141,1132」）。若未指定，則搜尋所有可用學期。",
      "default": null
    }
  ]
}

